1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
6	type StepResult = { premium: number };
7	type ScenarioResult = { results: StepResult[] };
8	
9	const BASE_PRICES: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	};
16	
17	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
18	
19	const sumBasePrices = (items: Item[]): number => {
20	  if (items.length === 3 && items.every((i) => i.type === "rune")) return 60;
21	  return items.reduce((sum, item) => sum + basePriceOf(item), 0);
22	};
23	
24	const quotePremium = (items: Item[]): number =>
25	  sumBasePrices(items) + PROCESSING_FEE;
26	
27	const runStep = (step: QuoteStep): StepResult => ({
28	  premium: quotePremium(step.items),
29	});
30	
31	export const runScenario = (input: Scenario): ScenarioResult => ({
32	  results: input.steps.map(runStep),
33	});
